import{c as e,Q as t,j as r,m as i}from"./chunks/framework.BA1dEi98.js";const o="/librislog/next/screenshots/admin-users.png",s="/librislog/next/screenshots/admin-backup.png",g=JSON.parse('{"title":"Administration","description":"","frontmatter":{},"headers":[],"relativePath":"guide/using-librislog/administration.md","filePath":"guide/using-librislog/administration.md","lastUpdated":1779870229000}'),n={name:"guide/using-librislog/administration.md"};function l(c,a,d,u,p,h){return t(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="administration" tabindex="-1">Administration <a class="header-anchor" href="#administration" aria-label="Permalink to &quot;Administration&quot;">​</a></h1><p>The administration page is available only to users with the <strong>admin</strong> role. Regular users cannot access it.</p><p><img src="'+o+'" alt="Users tab"></p><h2 id="users" tabindex="-1">Users <a class="header-anchor" href="#users" aria-label="Permalink to &quot;Users&quot;">​</a></h2><h3 id="creating-a-user" tabindex="-1">Creating a User <a class="header-anchor" href="#creating-a-user" aria-label="Permalink to &quot;Creating a User&quot;">​</a></h3><p>Admins can create new user accounts with either the <code>user</code> or <code>admin</code> role. The password must meet the complexity requirements displayed in the form.</p><h3 id="editing-a-user" tabindex="-1">Editing a User <a class="header-anchor" href="#editing-a-user" aria-label="Permalink to &quot;Editing a User&quot;">​</a></h3><p>Click &quot;Edit&quot; next to a user to change their name, email, password, or role. You cannot change your own admin role to prevent accidental lockout.</p><h3 id="deleting-a-user" tabindex="-1">Deleting a User <a class="header-anchor" href="#deleting-a-user" aria-label="Permalink to &quot;Deleting a User&quot;">​</a></h3><p>Click &quot;Delete&quot; to remove a user account. You cannot delete your own account from this page — use the <strong>Profile → Danger Zone</strong> instead.</p><h2 id="backup-restore" tabindex="-1">Backup &amp; Restore <a class="header-anchor" href="#backup-restore" aria-label="Permalink to &quot;Backup &amp; Restore&quot;">​</a></h2><p><img src="'+s+'" alt="Backup and Restore tab"></p><h3 id="creating-a-backup" tabindex="-1">Creating a Backup <a class="header-anchor" href="#creating-a-backup" aria-label="Permalink to &quot;Creating a Backup&quot;">​</a></h3><p>Downloads the entire SQLite database as a <code>.db</code> file. This is a complete snapshot of your library, users, and settings.</p><h3 id="restoring-a-backup" tabindex="-1">Restoring a Backup <a class="header-anchor" href="#restoring-a-backup" aria-label="Permalink to &quot;Restoring a Backup&quot;">​</a></h3><p>Upload a previously downloaded <code>.db</code> file to restore the database. The app validates the backup before applying it.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Restoring overwrites all current data. Create a fresh backup first if you want to preserve your current library.</p></div>',17)])])}const b=e(n,[["render",l]]);export{g as __pageData,b as default};
